import { useEffect, useState } from 'react';

import { ORIENTATION } from '../../../../constants.js';
import { useLegendSize } from '../../shared/context/LegendSizeContext.js';
import {
  MAX_LEGEND_WIDTH,
  MAX_LEGEND_HEIGHT,
  CONTAINER_PADDING,
} from '../constants.js';
import { useOrientation } from '../context/RangeLegendOrientationContext.js';
import { useScale } from '../context/RangeLegendScaleContext.js';
import { useRangeLegendTruncation } from '../context/RangeLegendTruncationContext.js';
import {
  HorizontalCoords,
  LabelAlignment,
  RangeLabel,
} from '../types/range-legend.internal.js';
import { handleCollisionInHorizontalLayout } from '../utils/handle-collision-in-horizontal-layout.js';
import { handleCollisionInVerticalLayout } from '../utils/handle-collision-in-vertical-layout.js';

/**
 * Hook responsible to detect and resolve the collisions for the intermediate labels.
 * The collision is relative to the bounds of the legend, meaning that if a
 * label will overflow the start segment or the end segment position, text truncation
 * will be applied.
 */
export const useLegendIntermediateLabelCollisionDetector = (
  labelText: string,
  segmentStartPosition: number,
  segmentEndPosition: number,
  alignment: LabelAlignment,
  skipCollisionDetector: boolean,
): RangeLabel => {
  const [label, setLabel] = useState<RangeLabel>({ text: labelText });

  const truncationMode = useRangeLegendTruncation();
  const { orientation } = useOrientation();
  const { scale } = useScale();
  const { width: legendWidth, height: legendHeight } = useLegendSize();

  const containerLegendHeight = legendHeight - CONTAINER_PADDING * 2;
  const containerLegendWidth = legendWidth - CONTAINER_PADDING * 2;

  const width = Math.min(containerLegendWidth, MAX_LEGEND_WIDTH);
  const height = Math.max(containerLegendHeight, MAX_LEGEND_HEIGHT);

  useEffect(() => {
    if (skipCollisionDetector || width <= 0 || height <= 0) {
      return;
    }

    const labelPosition: HorizontalCoords = {
      start: segmentStartPosition,
      end: segmentEndPosition,
    };

    if (orientation === ORIENTATION.Horizontal) {
      const newLabel = handleCollisionInHorizontalLayout(
        labelText,
        labelPosition,
        alignment,
        truncationMode,
        scale.range(),
      );

      setLabel(newLabel);
    } else {
      const newLabel = handleCollisionInVerticalLayout(
        labelText,
        labelPosition,
        alignment,
        truncationMode,
        scale.range(),
      );
      setLabel(newLabel);
    }
  }, [
    width,
    height,
    alignment,
    segmentStartPosition,
    segmentEndPosition,
    skipCollisionDetector,
    orientation,
    labelText,
    truncationMode,
    scale,
  ]);

  return label;
};
